-- Estrutura básica
BEGIN TRANSACTION;
    -- Comandos DML aqui
    UPDATE Contas SET Saldo = Saldo - 1000 WHERE Id = 1;
    UPDATE Contas SET Saldo = Saldo + 1000 WHERE Id = 2;
COMMIT TRANSACTION; -- confirma todas as alterações

-- Com ROLLBACK em caso de erro
BEGIN TRANSACTION;
    DELETE FROM Pedidos WHERE Status = 'Cancelado';
    -- ... outros comandos
ROLLBACK TRANSACTION; -- desfaz tudo desde o BEGIN

BEGIN TRANSACTION;
BEGIN TRY
    -- Transferência entre contas
    UPDATE Contas
    SET Saldo = Saldo - 500
    WHERE Id = 1;

    UPDATE Contas
    SET Saldo = Saldo + 500
    WHERE Id = 2;

    COMMIT TRANSACTION;
    PRINT 'Transferência realizada com sucesso.';
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
    PRINT 'Erro: ' + ERROR_MESSAGE();
END CATCH;

BEGIN TRANSACTION;
    INSERT INTO Log (Msg) VALUES ('Início');

    SAVE TRANSACTION PontoA;  -- savepoint

    UPDATE Produtos SET Preco = Preco * 0.9;  -- desconto 10%

    -- Só reverter até o savepoint, não a transação toda
    ROLLBACK TRANSACTION PontoA;

    -- O INSERT do Log ainda está ativo
COMMIT TRANSACTION;
